DATABASE_URL = os.environ.get("DATABASE_URL", "")
ADMIN_KEY    = os.environ.get("ADMIN_KEY", "neev2024admin")

# ── HINDI NUMERAL MAP ─────────────────────────────────────────────────────────
HINDI_DIGITS = str.maketrans("०१२३४५६७८९", "0123456789")

# ── DATABASE ──────────────────────────────────────────────────────────────────
def parse_db_url(url):
    m = re.match(r"postgresql://([^:]+):([^@]+)@([^:/]+):(\d+)/(.+)", url)
    if not m: raise ValueError("Bad DATABASE_URL format")
    return dict(user=m[1], password=m[2], host=m[3], port=int(m[4]), database=m[5])

def get_conn():
    p = parse_db_url(DATABASE_URL)
    conn = pg8000.dbapi.connect(
        user=p["user"], password=p["password"], host=p["host"],
        port=p["port"], database=p["database"], ssl_context=True)
    conn.autocommit = True
    return conn

def db_query(sql, args=()):
    conn = get_conn()
    try:
        cur = conn.cursor()
        cur.execute(sql, args)
        cols = [d[0] for d in cur.description]
        return [dict(zip(cols, r)) for r in cur.fetchall()]
    finally:
        conn.close()

def db_one(sql, args=()):
    rows = db_query(sql, args)
    return rows[0] if rows else None

def db_run(sql, args=()):
    conn = get_conn()
    try:
        cur = conn.cursor()
        cur.execute(sql, args)
        return cur.fetchone() if cur.description else None
    finally:
        conn.close()

def init_db():
    conn = get_conn()
    try:
        cur = conn.cursor()
        cur.execute("""CREATE TABLE IF NOT EXISTS distributors (
            id         SERIAL PRIMARY KEY,
            name       TEXT NOT NULL,
            pincode    TEXT NOT NULL,
            mobile     TEXT NOT NULL,
            address    TEXT NOT NULL,
            created_at TIMESTAMPTZ DEFAULT NOW(),
            updated_at TIMESTAMPTZ DEFAULT NOW()
        )""")
        cur.execute("SELECT COUNT(*) FROM distributors")
        count = cur.fetchone()[0]
        if count == 0:
            logging.info("Seeding %d distributors...", len(SEED_DATA))
            for d in SEED_DATA:
                cur.execute(
                    "INSERT INTO distributors (name,pincode,mobile,address) VALUES (%s,%s,%s,%s)",
                    (d["name"], d["pincode"], d["mobile"], d["address"]))
            logging.info("Seed complete.")
        else:
            logging.info("DB already has %d records.", count)
    finally:
        conn.close()

# ── AUTH ──────────────────────────────────────────────────────────────────────
def require_key(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        key = request.headers.get("X-Admin-Key") or request.args.get("key","")
        if key != ADMIN_KEY:
            return jsonify({"error":"Unauthorized"}), 401
        return f(*args, **kwargs)
    return decorated

