WX_CODE = {
    0:"☀️ साफ आसमान",1:"🌤️ ज्यादातर साफ",2:"⛅ आंशिक बादल",3:"☁️ बादल छाए",
    45:"🌫️ कोहरा",48:"🌫️ कोहरा",
    51:"🌦️ हल्की बूंदाबांदी",53:"🌦️ बूंदाबांदी",55:"🌧️ तेज बूंदाबांदी",
    61:"🌧️ हल्की बारिश",63:"🌧️ बारिश",65:"🌧️ तेज बारिश",
    80:"🌦️ बौछारें",81:"🌧️ तेज बौछारें",82:"⛈️ भारी बौछारें",
    95:"⛈️ आंधी-तूफान",99:"⛈️ ओलावृष्टि"
}
DAYS_HI = ["सोमवार","मंगलवार","बुधवार","गुरुवार","शुक्रवार","शनिवार","रविवार"]

def wx_label(code):
    for c in sorted(WX_CODE.keys(), reverse=True):
        if code >= c: return WX_CODE[c]
    return "🌡️ मौसम"

# Cache lat/lon per pincode to avoid Nominatim rate limits
_latlon_cache = {}

def pincode_to_latlon(pincode):
    if pincode in _latlon_cache:
        return _latlon_cache[pincode]
    url = "https://nominatim.openstreetmap.org/search?postalcode="+pincode+"&country=India&format=json&limit=1"
    req = urllib.request.Request(url, headers={"User-Agent":"NeevSeeds-Bot/1.0"})
    with urllib.request.urlopen(req, timeout=10) as r:
        data = json.loads(r.read())
    if not data: return None, None, None
    result = float(data[0]["lat"]), float(data[0]["lon"]), data[0].get("display_name","")
    _latlon_cache[pincode] = result
    return result

def get_forecast(lat, lon):
    url = ("https://api.open-meteo.com/v1/forecast?latitude="+str(lat)+"&longitude="+str(lon)+
           "&daily=weather_code,temperature_2m_max,temperature_2m_min,precipitation_sum,"
           "precipitation_probability_max,wind_speed_10m_max&timezone=Asia/Kolkata&forecast_days=7")
    with urllib.request.urlopen(url, timeout=10) as r:
        return json.loads(r.read())["daily"]

def format_weather_msg(pincode, daily, loc):
    parts = [p.strip() for p in loc.split(",")]
    city  = parts[1] if len(parts) > 1 else parts[0]
    lines = ["🌾 *"+city+" - 7 दिन का मौसम*\n(पिन: "+pincode+")\n"]
    for i in range(7):
        d  = datetime.strptime(daily["time"][i], "%Y-%m-%d")
        rm = daily["precipitation_sum"][i] or 0
        rp = daily["precipitation_probability_max"][i] or 0
        line = ("*"+DAYS_HI[d.weekday()]+" ("+d.strftime("%d %b")+")*\n"
                +wx_label(daily["weather_code"][i])+"\n"
                +"🌡 "+str(daily["temperature_2m_min"][i])+"°C – "+str(daily["temperature_2m_max"][i])+"°C")
        if rm > 0:    line += "\n🌧 बारिश: "+str(rm)+"mm ("+str(rp)+"%)"
        elif rp > 20: line += "\n🌧 बारिश संभव: "+str(rp)+"%"
        line += "\n💨 हवा: "+str(daily["wind_speed_10m_max"][i])+" km/h"
        lines.append(line)
        if i < 6: lines.append("—")
    lines.append("\n_स्रोत: Open-Meteo_")
    return "\n".join(lines)

# ── DISTRIBUTOR LOOKUP ────────────────────────────────────────────────────────
def find_nearest(pincode_str):
    pin_int = int(pincode_str)
    # Tier 1: exact match
    rows = db_query("SELECT * FROM distributors WHERE pincode = %s ORDER BY name", (pincode_str,))
    if rows: return rows[:5], "exact"
    # Tier 2: same sub-district (4-digit)
    rows = db_query("SELECT * FROM distributors WHERE pincode LIKE %s", (pincode_str[:4]+"%",))
    if rows:
        return sorted(rows, key=lambda r: abs(int(r["pincode"])-pin_int))[:5], "nearby"
    # Tier 3: same district (3-digit), closest 5
    rows = db_query("SELECT * FROM distributors WHERE pincode LIKE %s", (pincode_str[:3]+"%",))
    if rows:
        return sorted(rows, key=lambda r: abs(int(r["pincode"])-pin_int))[:5], "district"
    return [], None

def format_dist_msg(matches, level):
    labels = {"exact":"आपके क्षेत्र के","nearby":"आपके नजदीक के","district":"आपके जिले के"}
    lines  = ["✅ "+labels.get(level,"नजदीकी")+" *Neev Seeds* के "+str(len(matches))+" डिस्ट्रीब्यूटर:\n"]
    for i, d in enumerate(matches, 1):
        lines += ["*"+str(i)+". "+d["name"]+"*", "📍 "+d["address"], "📞 "+d["mobile"], ""]
    lines.append("किसी भी जानकारी के लिए डिस्ट्रीब्यूटर से सीधे संपर्क करें। 🙏")
    return "\n".join(lines)

def get_pincode():
    """Extract pincode from any request format. Handles integers, Hindi numerals,
       spaces, newlines, WATI integer type, and sentences containing a pincode."""
    if request.method == "POST":
        body = request.get_json(silent=True) or {}
        raw = str(body.get("pincode",""))
    else:
        raw = request.args.get("pincode","")
    # Translate Hindi numerals to ASCII
    raw = str(raw).translate(HINDI_DIGITS)
    # Find standalone 6-digit sequences not part of longer numbers
    found = re.findall(r"(?<!\d)\d{6}(?!\d)", raw)
    if found: return found[0]
    # Fallback: strip all non-digits, accept only if exactly 6
    digits = re.sub(r"\D", "", raw)
    return digits if len(digits) == 6 else None

# ── BOT ROUTES ────────────────────────────────────────────────────────────────
@app.route("/find", methods=["GET","POST"])
def find_distributors():
    pincode = get_pincode()
    logging.info("FIND | pin=%s | ua=%s", pincode, request.headers.get("User-Agent","")[:30])
    if not pincode:
        return jsonify({
            "count": 0,
            "message": "❌ पिनकोड सही नहीं है।\nकृपया 6 अंकों का पिनकोड भेजें।\nजैसे: *152116*"
        }), 400
    try:
        matches, level = find_nearest(pincode)
        if not matches:
            return jsonify({
                "count": 0,
                "message": ("📍 पिनकोड "+pincode+" के पास अभी कोई Neev Seeds डिस्ट्रीब्यूटर नहीं है।\n\n"
                            "अधिक जानकारी के लिए Neev Seeds से सीधे संपर्क करें। 🙏")
            })
        return jsonify({
            "count":       len(matches),
            "match_level": level,
            "message":     format_dist_msg(matches, level),
            "distributors": [
                {
                    "Distributor Name": d["name"],
                    "Address":          d["address"],
                    "Mobile Number":    d["mobile"]
                }
                for d in matches
            ]
        })
    except Exception as e:
        logging.error("FIND ERROR pin=%s: %s", pincode, e)
        return jsonify({
            "count": 0,
            "message": "⚠️ अभी जानकारी नहीं मिल पाई। कृपया थोड़ी देर बाद पुनः प्रयास करें।"
        }), 500

@app.route("/weather", methods=["GET","POST"])
def weather():
    pincode = get_pincode()
    if not pincode:
        return jsonify({"message":"❌ कृपया सही 6 अंकों का पिनकोड भेजें।"}), 400
    try:
        lat, lon, loc = pincode_to_latlon(pincode)
        if not lat:
            return jsonify({"message":"📍 पिनकोड "+pincode+" की लोकेशन नहीं मिली।"})
        daily = get_forecast(lat, lon)
        return jsonify({"pincode":pincode,"location":loc,"message":format_weather_msg(pincode,daily,loc)})
    except Exception as e:
        logging.error("WEATHER ERROR pin=%s: %s", pincode, e)
        return jsonify({"message":"⚠️ मौसम जानकारी अभी उपलब्ध नहीं। बाद में प्रयास करें। 🙏"}), 500

