@app.route("/admin/ping")
@require_key
def admin_ping():
    return jsonify({"ok": True})

@app.route("/admin/distributors", methods=["GET"])
@require_key
def list_distributors():
    try:
        s = request.args.get("q","").strip()
        if s:
            rows = db_query(
                "SELECT * FROM distributors WHERE name ILIKE %s OR pincode ILIKE %s OR address ILIKE %s ORDER BY name",
                ("%"+s+"%", "%"+s+"%", "%"+s+"%"))
        else:
            rows = db_query("SELECT * FROM distributors ORDER BY name")
        # Convert datetime to string for JSON
        for r in rows:
            for k in ("created_at","updated_at"):
                if k in r and r[k]: r[k] = str(r[k])
        return jsonify(rows)
    except Exception as e:
        logging.error("LIST ERROR: %s", e)
        return jsonify({"error": str(e)}), 500

@app.route("/admin/distributors", methods=["POST"])
@require_key
def add_distributor():
    data    = request.get_json(silent=True) or {}
    name    = data.get("name","").strip()
    pincode = re.sub(r"\D","", str(data.get("pincode","")).translate(HINDI_DIGITS))
    mobile  = data.get("mobile","").strip()
    address = data.get("address","").strip()
    if not all([name, pincode, mobile, address]):
        return jsonify({"error":"All fields required: name, pincode, mobile, address"}), 400
    if len(pincode) != 6:
        return jsonify({"error":"Pincode must be exactly 6 digits"}), 400
    try:
        row = db_run(
            "INSERT INTO distributors (name,pincode,mobile,address) VALUES (%s,%s,%s,%s) RETURNING id",
            (name, pincode, mobile, address))
        return jsonify({"id": row[0], "message":"Distributor added successfully"}), 201
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route("/admin/distributors/<int:rid>", methods=["GET"])
@require_key
def get_distributor(rid):
    row = db_one("SELECT * FROM distributors WHERE id = %s", (rid,))
    if not row: return jsonify({"error":"Not found"}), 404
    for k in ("created_at","updated_at"):
        if k in row and row[k]: row[k] = str(row[k])
    return jsonify(row)

@app.route("/admin/distributors/<int:rid>", methods=["PUT"])
@require_key
def update_distributor(rid):
    row = db_one("SELECT * FROM distributors WHERE id = %s", (rid,))
    if not row: return jsonify({"error":"Not found"}), 404
    data    = request.get_json(silent=True) or {}
    name    = data.get("name", row["name"]).strip()
    pincode = re.sub(r"\D","", str(data.get("pincode", row["pincode"])).translate(HINDI_DIGITS))
    mobile  = data.get("mobile", row["mobile"]).strip()
    address = data.get("address", row["address"]).strip()
    if len(pincode) != 6:
        return jsonify({"error":"Pincode must be exactly 6 digits"}), 400
    try:
        db_run("UPDATE distributors SET name=%s,pincode=%s,mobile=%s,address=%s,updated_at=NOW() WHERE id=%s",
               (name, pincode, mobile, address, rid))
        return jsonify({"message":"Updated successfully"})
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route("/admin/distributors/<int:rid>", methods=["DELETE"])
@require_key
def delete_distributor(rid):
    row = db_one("SELECT * FROM distributors WHERE id = %s", (rid,))
    if not row: return jsonify({"error":"Not found"}), 404
    db_run("DELETE FROM distributors WHERE id = %s", (rid,))
    return jsonify({"message":"Deleted successfully"})

